import{_ as e,c as t,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"プラットフォーム対応: クォータ照会 | opencode-mystatus","description":"opencode-mystatusがサポートする4つのAIプラットフォームを学びます。OpenAI、Zhipu AI、GitHub Copilot、Google Cloudのクォータ照会に対応。","frontmatter":{"title":"プラットフォーム対応: クォータ照会 | opencode-mystatus","sidebarTitle":"プラットフォーム機能","subtitle":"プラットフォーム対応: クォータ照会","description":"opencode-mystatusがサポートする4つのAIプラットフォームを学びます。OpenAI、Zhipu AI、GitHub Copilot、Google Cloudのクォータ照会に対応。","order":2},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/platforms/index.md","filePath":"ja/vbgate/opencode-mystatus/platforms/index.md"}'),l={name:"ja/vbgate/opencode-mystatus/platforms/index.md"};function r(d,a,u,n,s,h){return o(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="プラットフォーム機能" tabindex="-1">プラットフォーム機能 <a class="header-anchor" href="#プラットフォーム機能" aria-label="Permalink to &quot;プラットフォーム機能&quot;">​</a></h1><p>この章では、opencode-mystatusがサポートする各AIプラットフォームのクォータクエリ機能を詳しく紹介します。</p><h2 id="サポートされるプラットフォーム" tabindex="-1">サポートされるプラットフォーム <a class="header-anchor" href="#サポートされるプラットフォーム" aria-label="Permalink to &quot;サポートされるプラットフォーム&quot;">​</a></h2><p>opencode-mystatusは以下の4つの主流AIプラットフォームをサポートしています：</p><table tabindex="0"><thead><tr><th>プラットフォーム</th><th>クォータタイプ</th><th>特徴</th></tr></thead><tbody><tr><td>OpenAI</td><td>3時間 / 24時間スライディングウィンドウ</td><td>Plus、Team、Proサブスクリプションをサポート</td></tr><tr><td>Zhipu AI</td><td>5時間 Token / MCP 月次クォータ</td><td>Coding Planをサポート</td></tr><tr><td>GitHub Copilot</td><td>月次クォータ</td><td>Premium Requests使用量を表示</td></tr><tr><td>Google Cloud</td><td>モデル別計算</td><td>複数アカウント、4つのモデルをサポート</td></tr></tbody></table><h2 id="プラットフォームの詳解" tabindex="-1">プラットフォームの詳解 <a class="header-anchor" href="#プラットフォームの詳解" aria-label="Permalink to &quot;プラットフォームの詳解&quot;">​</a></h2><h3 id="openai-クォータ" tabindex="-1"><a href="./openai-usage/">OpenAI クォータ</a> <a class="header-anchor" href="#openai-クォータ" aria-label="Permalink to &quot;[OpenAI クォータ](./openai-usage/)&quot;">​</a></h3><p>OpenAIのクォータクエリメカニズムを深く理解します：</p><ul><li>3時間と24時間スライディングウィンドウの違い</li><li>チームアカウントのクォータ共有メカニズム</li><li>JWT Token解析でアカウント情報を取得</li></ul><h3 id="zhipu-ai-クォータ" tabindex="-1"><a href="./zhipu-usage/">Zhipu AI クォータ</a> <a class="header-anchor" href="#zhipu-ai-クォータ" aria-label="Permalink to &quot;[Zhipu AI クォータ](./zhipu-usage/)&quot;">​</a></h3><p>Zhipu AIとZ.aiのクォータクエリを理解します：</p><ul><li>5時間Tokenクォータの計算方式</li><li>MCP月次クォータの用途</li><li>APIキーマスキング表示</li></ul><h3 id="github-copilot-クォータ" tabindex="-1"><a href="./copilot-usage/">GitHub Copilot クォータ</a> <a class="header-anchor" href="#github-copilot-クォータ" aria-label="Permalink to &quot;[GitHub Copilot クォータ](./copilot-usage/)&quot;">​</a></h3><p>GitHub Copilotのクォータ管理をマスターします：</p><ul><li>Premium Requestsの意味</li><li>異なるサブスクリプションタイプのクォータ差異</li><li>月次リセット時間の計算</li></ul><h3 id="google-cloud-クォータ" tabindex="-1"><a href="./google-usage/">Google Cloud クォータ</a> <a class="header-anchor" href="#google-cloud-クォータ" aria-label="Permalink to &quot;[Google Cloud クォータ](./google-usage/)&quot;">​</a></h3><p>Google Cloud複数アカウントのクォータクエリを学びます：</p><ul><li>4つのモデル（G3 Pro、G3 Image、G3 Flash、Claude）の違い</li><li>複数アカウント管理と切り替え</li><li>認証ファイル読み取りメカニズム</li></ul><h2 id="選択ガイド" tabindex="-1">選択ガイド <a class="header-anchor" href="#選択ガイド" aria-label="Permalink to &quot;選択ガイド&quot;">​</a></h2><p>使用しているプラットフォームに応じて、対応するチュートリアルを選択してください：</p><ul><li><strong>OpenAIのみを使用</strong>：直接 <a href="./openai-usage/">OpenAI クォータ</a> を見る</li><li><strong>Zhipu AIのみを使用</strong>：直接 <a href="./zhipu-usage/">Zhipu AI クォータ</a> を見る</li><li><strong>マルチプラットフォームユーザー</strong>：すべてのプラットフォームチュートリアルを順に読むことをお勧め</li><li><strong>Google Cloudユーザー</strong>：先に <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> プラグインをインストールする必要があります</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を完了したら、<a href="./../advanced/">高度な機能</a>を続けて学び、より多くの設定オプションを理解できます。</p>',23)])])}const g=e(l,[["render",r]]);export{c as __pageData,g as default};
